  "title": "Functional and morphometric outcome of adaptable slicing condylectomy in transverse condylar hyperplasia: A deep learning-enhanced 3D study",
  "authors": [
   "Spallaccia F",
   "Committeri U",
   "Giovannoni M E",
   "Ricciardi A",
   "Cascone P"
  ],
  "journal": "Journal of cranio-maxillo-facial surgery : official publication of the European Association for Cranio-Maxillo-Facial Surgery",
  "doi": "10.1016/j.jcms.2026.104649",
  "pmid": "42418925",
  "url": "https://pubmed.ncbi.nlm.nih.gov/42418925/",
