  "title": "Metabolic Syndrome and Risk of Atrial Fibrillation in Chronic Kidney Disease",
  "authors": [
   "Ravi Katherine Scovner",
   "Mc Causland Finnian R"
  ],
  "journal": "American journal of nephrology",
  "doi": "10.1159/000553385",
  "pmid": "42391142",
  "url": "https://pubmed.ncbi.nlm.nih.gov/42391142/",
  "pubdate": "2026-07-02",
  "date": "2026-07-03",
  "tags": [
   "scraped",
   "pubmed"
  ],
  "confidence": "medium",
